        jsonOutput ? '' : 'PRAGMA journal_mode = WAL;',
        jsonOutput ? '' : 'PRAGMA synchronous = NORMAL;',
        jsonOutput ? '' : 'PRAGMA foreign_keys = ON;',
        script
